    "song_title": "Alexander Hamilton",
    "song_title_zh": "",
    "song_id": "01-alexander-hamilton",
    "line_index": "32",
    "english": "Moved in with a cousin, the cousin committed suicide",
    "ipa": "/muvd ɪn wɪð ə kʌzən ðə kʌzən kəmɪtɪd suɪsaɪd/",
