    "song_title_zh": "",
    "song_id": "04-the-story-of-tonight",
    "line_index": "3",
    "english": "But I will gladly join the fight!",
    "ipa": "/bʌt aɪ wɪl ɡlædli dʒɔɪn ðə faɪt/",
