    "song_title_zh": "",
    "song_id": "04-the-story-of-tonight",
    "line_index": "12",
    "english": "Something they can never take away",
    "ipa": "/sʌmθɪŋ ðeɪ kæn nɛvɚ teɪk əweɪ/",
    "chinese_translation": "他们无法将此抢夺",
