    "song_order": "5",
    "song_title": "The Schuyler Sisters",
    "song_title_zh": "",
    "song_id": "05-the-schuyler-sisters",
    "line_index": "57",
    "english": "So listen to my declaration:",
    "ipa": "/soʊ lɪsən tə maɪ dɛkləreɪʃən/",
    "chinese_translation": "仔细听好我的宣言声明：",
