    "song_title_zh": "",
    "song_id": "11-satisfied",
    "line_index": "40",
    "english": "I remember those soldier boys",
    "ipa": "/aɪ rɪmɛmbɚ ðoʊz soʊldʒɚ bɔɪz/",
    "chinese_translation": "我记得那些年轻的士兵们",
