    "song_title_zh": "",
    "song_id": "13-wait-for-it",
    "line_index": "73",
    "english": "He plays and he raises the stakes",
    "ipa": "/hi pleɪz ænd hi reɪzɪz ðə steɪks/",
    "chinese_translation": "他精于变通，还提高了筹码",
