    "song_id": "13-wait-for-it",
    "line_index": "77",
    "english": "I'm willing to wait for it...",
    "ipa": "/aɪm wɪlɪŋ tə weɪt fɔr ɪt/",
    "chinese_translation": "等待时机再出手",
