    "song_title_zh": "",
    "song_id": "13-wait-for-it",
    "line_index": "85",
    "english": "When so many have died",
    "ipa": "/wɛn soʊ mɛni hæv daɪd/",
    "chinese_translation": "尽管那么多人已死去",
    "note": "",
