    "song_title_zh": "",
    "song_id": "40-stay-alive-reprise",
    "line_index": "25",
    "english": "I know, I know",
    "ipa": "/aɪ noʊ aɪ noʊ/",
    "chinese_translation": "我知道，我知道",
    "note": "",
