    "song_title": "Stay Alive (Reprise)",
    "song_title_zh": "",
    "song_id": "40-stay-alive-reprise",
    "line_index": "44",
    "english": "Un deux trois quatre",
    "ipa": "/ʌn dju twɑ kwætɚ/",
