    "song_title": "Stay Alive (Reprise)",
    "song_title_zh": "",
    "song_id": "40-stay-alive-reprise",
    "line_index": "45",
    "english": "Cinq six sept huit neuf",
    "ipa": "/sɪŋk sɪks sɛpt hjuɪt nuf/",
    "chinese_translation": "五 六 七 八 九",
