    "song_title_zh": "",
    "song_id": "42-the-election-of-1800",
    "line_index": "49",
    "english": "Alexander!",
    "ipa": "/ælɪɡzændɚ/",
    "chinese_translation": "亚历山大！",
    "note": "",
    "source_file": "Hamilton (Original Broadway Cast Recording) (3367211).md"
